"""
MKT Original Commentary — Matthew chapters 15–17
Run: python3 scripts/zc-original-matthew-15-17.py

Source data used:
- data/interlinear/matthew.json
- data/translation/draft/mediating/matthew.json
- data/commentary/mkt-original/matthew.json (existing ch1-14 carried forward)

Key decisions in this range:
- 15:2: paradosis tōn presbyterōn — oral tradition, not Scripture; the
  controversy is tradition vs. Scripture
- 15:5: korban — transliterated Aramaic oath-formula; the Corban declaration
- 15:22: Chananaios — "Canaanite" is a deliberately archaic ethnic label (LXX
  usage) not merely "Syro-Phoenician" (Mark's term)
- 15:26: kynarion — diminutive "little dogs/puppies" (not the derogatory kuōn)
- 15:36: eucharistēsas — second feeding uses eucharistēsas (gave thanks) vs.
  14:19 eulogēsen (blessed); the shift from berakah to eucharistia
- 15:37: spyris — a different basket word from kophinos in ch14; spyris is
  a large hamper/basket, different vessel
- 16:18: Petros/petra — the wordplay operates differently in Greek vs. Aramaic;
  noted as a well-worn debate
- 16:18: pulai haidou — gates of Hades/the underworld, not hell in the modern
  sense; gates = power/authority of the realm of death
- 16:19: dedemenon/lelumenon — perfect passives in heaven may indicate "will
  have been bound/loosed" not simple future
- 16:21: apo tote ērxato — structural formula marking a new phase in the Gospel
- 16:22: ileos soi — "God forbid/be merciful to you" not a general interjection
- 17:2: metemorphōthē — transfigured from within, not external disguise
- 17:20: metabēsomai — the mountain-moving faith saying uses the future indicative
  of metabainō
- 17:27: stater — one stater = four drachmas = one shekel = two people's
  annual temple tax
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MATTHEW = {
  "15": {
    "1": '<p><strong>tote proserchontai tō Iēsou apo Ierosolymōn Pharisaioi kai grammateis</strong> — then Pharisees and scribes come to Jesus from Jerusalem (<em>apo Ierosolymōn</em>: from Jerusalem — this is not a local Galilean confrontation but a delegation from the religious capital; the phrase signals official, institutional opposition): the Jerusalem origin elevates the confrontation; these are not provincial critics but representatives of the establishment. The timing ("then") connects the purity controversy to the Gentile expansion hinted at in the feeding of ch14.</p>',
    "2": '<p><strong>dia ti hoi mathētai sou parabainousin tēn paradosin tōn presbyterōn</strong> — why do your disciples transgress the tradition of the elders (<em>paradosis tōn presbyterōn</em>: the tradition of the elders — <em>paradosis</em>, that which is handed down, a transmitted tradition; <em>presbyterōn</em>, elders: the oral tradition attributed to revered predecessors, not the Torah itself) — <em>ou gar niptontai tas cheiras autōn hotan arton esthiōsin</em> (for they do not wash their hands when they eat bread): the charge is violation of oral-traditional purity rules, not a Mosaic command. The handwashing regulation is Pharisaic extension, not Sinai legislation.</p>',
    "3": '<p><strong>dia ti kai hymeis parabainete tēn entolēn tou theou dia tēn paradosin hymōn</strong> — why do you also transgress the commandment of God for the sake of your tradition? — Jesus\'s counter-accusation inverts the charge: the Pharisees accuse the disciples of breaking human tradition; Jesus accuses the Pharisees of breaking divine commandment. <em>Dia tēn paradosin hymōn</em> (for the sake of your tradition — <em>dia</em> with the accusative: on account of, motivated by): tradition is the cause; the violated commandment is the effect. The Corban example (vv.4-6) is the evidence.</p>',
    "4": '<p><strong>ho gar theos eipen tima ton patera kai tēn mētera</strong> — for God said: honor your father and mother (Exod 20:12; Deut 5:16) — <em>kai ho kakologōn patera ē mētera thanatō teleutatō</em> (and whoever speaks evil of father or mother, let them die — <em>kakologōn</em> present participle of <em>kakologeō</em>: to speak evil, to curse; <em>thanatō teleutatō</em>: let them die by death — the intensive idiom from Exod 21:17): the two commandments are placed together as a unit — the Fifth Commandment (honor) and the death penalty for its inversion (cursing). The positive and negative frame the absolute importance God attaches to parental honor.</p>',
    "5": '<p><strong>hymeis de legete hos an eipē tō patri ē tē mētri</strong> — but you say: whoever says to his father or mother — <em>dōron ho ean ex emou ōphelēthēs</em> (a gift — whatever you would have received from me is Corban/devoted to God — <em>dōron</em>: a gift, an offering): the Corban formula (<em>korban</em> in Mark 7:11, Aramaic for dedicated offering) allowed a person to declare property "devoted to God" as a vow, thereby making it legally unavailable to parents even while the person retained practical use of it. The declaration was a legal evasion of the Fifth Commandment\'s financial obligations.</p>',
    "6": '<p><strong>kai ou mē timēsei ton patera autou</strong> — and he will not honor his father (<em>ou mē</em> + subjunctive: emphatic negation — will certainly not honor him) — <em>kai ēkyrōsate ton logon tou theou dia tēn paradosin hymōn</em> (and you have nullified the word of God for the sake of your tradition — <em>ēkyrōsate</em> aorist of <em>akyroō</em>: to invalidate, make void — a legal term for annulling a binding decree): the accusation is precise: the oral tradition does not supplement but cancels the divine command. <em>Ton logon tou theou</em> (the word of God) is the same phrase used in 13:19 for the word of the kingdom.</p>',
    "7": '<p><strong>hypokritai kalōs eprophēteusen peri hymōn Ēsaias</strong> — hypocrites, Isaiah prophesied well about you (<em>hypokritai</em>: actors, those who play a role while concealing their true identity — the theatrical word now established as Jesus\'s standard term for the Pharisees; cf. 6:2,5,16; 23:13-29) — <em>kalōs eprophēteusen</em> (prophesied well/rightly): the Isaiah citation is not a forced application but an exact match; Isaiah described them before they existed, which Jesus calls prophesying "well" (accurately, fittingly).</p>',
    "9": '<p><strong>matēn de sebontai me didaskontes didaskalias entalmata anthrōpōn</strong> — they worship me in vain, teaching as teachings commandments of men (<em>matēn</em>: in vain, for nothing, pointlessly — an adverb of futility; <em>sebontai</em>: they revere, worship — the worship is genuine in form but empty in content) — <em>didaskalias entalmata anthrōpōn</em> (commandments of men as teachings — <em>entalma</em>: a commandment, a prescribed rule; the phrase echoes Isa 29:13 LXX): the Corban ruling is not a marginal case but the symptom of a systemic substitution of human prescription for divine command.</p>',
    "10": '<p><strong>kai proskalesamenos ton ochlon eipen autois</strong> — calling the crowd to him he said to them — <em>akouete kai syniete</em> (hear and understand — <em>akouete</em> present imperative: keep hearing; <em>syniete</em> present imperative: keep putting it together, keep understanding): the double imperative invites the crowd into the purity debate that the Pharisees framed as purely internal to the tradition. Jesus makes the issue public, democratizing what the scribal system had restricted to expert debate.</p>',
    "11": '<p><strong>ou to eisercomenon eis to stoma koinoi ton anthrōpon</strong> — not what enters the mouth defiles the person (<em>koinoi</em> present of <em>koinoō</em>: to make common, to defile ritually — <em>koinos</em> means common in the sense of ordinary/unclean, not the sacral category) — <em>alla to ekporeuomenon ek tou stomatos touto koinoi ton anthrōpon</em> (but what goes out of the mouth, this defiles the person): the statement is revolutionary — it relocates the locus of defilement from external contact (food, handwashing) to internal production (speech, and by implication thought; v.18-19 makes this explicit). Mark adds "thus he declared all foods clean" (7:19).</p>',
    "12": '<p><strong>tote proselthontes hoi mathētai legousin autō</strong> — then the disciples coming said to him — <em>oidas hoti hoi Pharisaioi akousantes ton logon eskandalisthēsan</em> (do you know that the Pharisees hearing the word were offended/caused to stumble — <em>eskandalisthēsan</em> aorist passive of <em>skandalizō</em>: were caused to stumble, took offense; the word carries the connotation of a fatal tripping, not mere irritation): the disciples are worried about the political fallout. Jesus\'s response (vv.13-14) does not address the politics but judges the Pharisees\' spiritual root.</p>',
    "13": '<p><strong>pasa phyteia hēn ouk ephyteusen ho patēr mou ho ouranios ekrizōthēsetai</strong> — every plant that my heavenly Father has not planted will be uprooted (<em>phyteia</em>: a planting, something planted — <em>phyteuō</em>: to plant; <em>ekrizōthēsetai</em> future passive of <em>ekrizoō</em>: to uproot, pull up by the roots): the imagery of planting and uprooting echoes the parable of the wheat and tares (13:24-30) and the Baptist\'s warning (3:10: "every tree not bearing good fruit is cut down"). The heavenly Father as the gardener determines what survives the final assessment.</p>',
    "14": '<p><strong>aphete autous typhlos eisin hodēgoi</strong> — leave them; they are blind guides (<em>typhlos hodēgoi</em>: blind guides — the compound describes their double failure: they lead without sight) — <em>typhlon de typhlos ean hodēgē</em> (if blind leads blind — the two blindnesses in the chain) — <em>amphoteroi eis bothynon pesountai</em> (both will fall into a pit — <em>bothynon</em>: a hole in the ground, a well-pit): the Pharisees are not merely wrong but actively dangerous to their followers. The image was proverbial in antiquity; Jesus applies the proverb with precision to the situation of Israel\'s religious leadership.</p>',
    "15": '<p><strong>apokritheis de ho Petros eipen autō phrason hēmin tēn parabolēn</strong> — Peter answering said to him: explain the parable to us (<em>phrason</em> aorist imperative of <em>phrazō</em>: to explain, point out, indicate clearly) — the request uses the parable-explanation vocabulary of 13:36, where the disciples asked for the weeds-parable explanation. Peter is asking for the private decoding the disciples received in ch13. The disciples are still in the transitional state between public parable-hearing and private parable-understanding.</p>',
    "16": '<p><strong>ho de eipen akmēn kai hymeis asyneti este</strong> — he said: are you still also without understanding (<em>akmēn</em>: still, even now — a classical Greek adverb marking continuation of a state; <em>asyneti</em>: without understanding — <em>a</em>- privative + <em>synetos</em>, the adjective from <em>syniēmi</em>: lacking the faculty of synthesis/comprehension): the gentle rebuke connects to the understanding-vocabulary of ch13. The disciples, though privileged to receive explanations, are still not fully understanding.</p>',
    "17": '<p><strong>ou noeite hoti pan to eisporeuomenon eis to stoma eis tēn koilian chōrei</strong> — do you not perceive that everything entering the mouth goes into the stomach (<em>noeite</em> present of <em>noeō</em>: to perceive, apprehend intellectually — the cognitive dimension of understanding; the stomach serves only as a way-station, not a defiler) — <em>kai eis aphedrōna ekballetai</em> (and is cast out into the latrine — <em>aphedrōn</em>: privy, toilet — a frank anatomical term): the digestive argument is deliberately physical; food passes through and out of the body without leaving a lasting moral trace. The moral life is not determined by what the body processes.</p>',
    "18": '<p><strong>ta de ekporeuomena ek tou stomatos ek tēs kardias exerchetai</strong> — but what comes out of the mouth comes from the heart (<em>exerchetai</em> present: comes out, flows out — a continuous outward flow from the inner source; <em>kardia</em>: the heart as the center of will, desire, intention, and moral character in Jewish anthropology) — <em>kakeina koinoi ton anthrōpon</em> (and those things defile the person — <em>kakeina</em>: and those things; the pronoun refers to the mouth\'s outputs that originate in the heart): the principle reverses the Pharisaic framework — purity is an inside-out matter, not an outside-in ritual.</p>',
    "19": '<p><strong>ek gar tēs kardias exerchontai dialogismoi ponēroi</strong> — for out of the heart come evil deliberations/thoughts (<em>dialogismoi ponēroi</em>: evil deliberations — <em>dialogismos</em>: a reasoning, calculation, deliberate thought; not passing emotions but considered choices that lead to action) — the list that follows covers the second table of the Decalogue plus extensions: <em>phonoi</em> (murders), <em>moicheiai</em> (adulteries), <em>porneiai</em> (sexual immoralities), <em>klopai</em> (thefts), <em>pseudomarturiai</em> (false testimonies), <em>blasphēmiai</em> (slanders/blasphemies): six plural nouns covering the full range of interpersonal and religious violations. The heart is the origin of all of these, not external contamination.</p>',
    "20": '<p><strong>tauta estin ta koinounta ton anthrōpon</strong> — these are the things that defile the person — <em>to de aniptois chersin phagein ou koinoi ton anthrōpon</em> (but eating with unwashed hands does not defile the person): the return to the original charge (v.2) completes the argument. The purity controversy is resolved not by lowering the standard of purity but by relocating it: unwashed-hands eating is a non-issue; speaking from an evil heart is the real defilement. The verdict is direct and unambiguous — "does not defile" (<em>ou koinoi</em>).</p>',
    "21": '<p><strong>kai exelthōn ekeithen ho Iēsous anechōrēsen eis ta merē Tyrou kai Sidōnos</strong> — going out from there Jesus withdrew to the regions of Tyre and Sidon (<em>anechōrēsen</em>: withdrew — the deliberate-withdrawal verb; <em>ta merē Tyrou kai Sidōnos</em>: the regions of Tyre and Sidon — the non-Jewish northwest coastal territories): the Canaanite woman encounter happens in Gentile territory — a geographical shift that frames her faith as exceptional precisely because she is outside the covenant. The cities Jesus denounced in 11:21-22 for not repenting are now the setting for a faith-encounter.</p>',
    "22": '<p><strong>kai idou gynē Chananaios apo tōn horiōn ekeinōn exelthousa ekrazen</strong> — and behold, a Canaanite woman from those regions came out and cried (<em>Chananaios</em>: Canaanite — an archaic LXX ethnic label for the pre-Israelite inhabitants of the land; Mark 7:26 uses "Syro-Phoenician" as the contemporary geographic term. Matthew\'s use of the archaic name invokes the covenant-history of Canaan and Israel) — <em>kyrie huie Dauid eleēson me</em> (Lord, Son of David, have mercy on me — the Davidic-Messiah address from a Canaanite, not an Israelite; she knows the messianic title even outside the covenant community).</p>',
    "23": '<p><strong>ho de ouk apekrithē autē logon</strong> — but he did not answer her a word (<em>ouk apekrithē autē logon</em>: the idiom is literally "did not answer her a word" — a complete, deliberate silence): the silence is not indifference but a test. The disciples\' response — <em>apoluson autēn hoti krazei opisthen hēmōn</em> (send her away, for she keeps crying after us) — is ambiguous: they may want her dismissed or want Jesus to grant her request so she stops following. Either way, their motive is self-interest, not compassion.</p>',
    "24": '<p><strong>ouk apestellēn ei mē eis ta probata ta apolōlota oikou Israēl</strong> — I was sent only to the lost sheep of the house of Israel (<em>ouk...ei mē</em>: not...except, only; the exclusive limitation is stated directly; <em>ta probata ta apolōlota</em>: the lost sheep — perfect passive participle of <em>apollymi</em>: the sheep in a state of lostness; echoing 10:6 where the disciples were sent to the same lost sheep) — the limitation is not permanent (28:19 gives the universal commission) but is the scope of the earthly mission to Israel. The Canaanite woman\'s faith will overcome this territorial limitation.</p>',
    "25": '<p><strong>hē de elthousa prosekynei autō legousa kyrie boēthei moi</strong> — but she came and was worshipping him saying: Lord, help me (<em>prosekynei</em> imperfect: was continuously worshipping, kneeling — an ongoing posture of petition; <em>boēthei</em> present imperative of <em>boētheō</em>: help, assist — <em>boē</em> + <em>theō</em>: run to a cry): the woman persists despite the silence and the limitation-statement. Her address shifts from "Son of David" (messianic title) to "Lord" (<em>kyrie</em>, the personal address of relationship), marking an escalation of intimacy in her appeal.</p>',
    "26": '<p><strong>ouk estin kalon labein ton arton tōn teknōn kai balein tois kynarois</strong> — it is not good to take the children\'s bread and throw it to the little dogs (<em>kalon</em>: good, appropriate, fitting; <em>teknōn</em>: children, the covenant people; <em>kynarois</em>: diminutive — little dogs, puppies, house dogs — not the derogatory <em>kyōn</em> of 7:6 but the domestic diminutive, softening the comparison): the image sets up the woman\'s response. The diminutive <em>kynarion</em> leaves space for the response of v.27 — household dogs eat under the table alongside the children.</p>',
    "27": '<p><strong>hē de eipen nai kyrie kai gar ta kynarion esthiei apo tōn psichion</strong> — but she said: yes Lord, for even the little dogs eat from the crumbs (<em>nai</em>: yes — she accepts the comparison without resentment; <em>kai gar</em>: for even, precisely because of this: the particle combination accepts and extends the argument) — <em>tōn piptontōn apo tēs trapezēs tōn kyriōn autōn</em> (that fall from the table of their masters — <em>trapezēs tōn kyriōn autōn</em>: the masters\' table): she takes the image and turns it: if she is a household dog, then the crumbs of the children\'s meal are still a share in it. Her argument is not a claim of equality but of proximity.</p>',
    "28": '<p><strong>tote apokritheis ho Iēsous eipen autē ō gynai megalē sou hē pistis</strong> — then answering Jesus said to her: O woman, your faith is great (<em>megalē sou hē pistis</em>: your faith is great — <em>megalē</em>, the adjective of greatness; the contrast with the disciples\' <em>oligopistia</em> is sharp: the Canaanite woman receives the superlative-positive while the disciples repeatedly receive the negative) — <em>genēthētō soi hōs theleis</em> (let it be done for you as you wish — <em>genēthētō</em> aorist passive imperative: let it become, let it happen — the same form as "your will be done" in the Lord\'s Prayer). <em>Kai iathē hē thygatēr autēs apo tēs hōras ekeinēs</em> — her daughter was healed from that hour.</p>',
    "29": '<p><strong>kai metabas ekeithen ho Iēsous ēlthen para tēn thalassan tēs Galilaias</strong> — moving on from there Jesus came alongside the Sea of Galilee (<em>metabas</em> aorist participle of <em>metabainō</em>: having moved on from one place to another; the verb marks deliberate geographical transition) — <em>kai anabas eis to oros ekathēto ekei</em> (and going up on the mountain he was sitting there — <em>ekathēto</em> imperfect: was sitting in the teaching position): the mountainside setting for the healing summary deliberately echoes the Sermon on the Mount (5:1). Jesus sits in the position of the authoritative teacher; the healings that follow are the teacher\'s actions, not merely miracles.</p>',
    "30": '<p><strong>kai prosēlthon autō ochloi polloi echontes meth heautōn chōlous typhlous</strong> — and large crowds came to him having with them lame, blind — the list continues: <em>kyllous</em> (crippled), <em>kōphous</em> (mute/deaf), and many others. <em>Kai erripsan autous para tous podas autou</em> (and cast them at his feet — <em>erripsan</em> aorist of <em>rhiptō</em>: to throw down, cast at the feet — the same verb used in 9:36 for the crowds being "cast down" like helpless sheep): the casting at Jesus\'s feet is a formal act of bringing helpless people to the healer\'s authority. <em>Kai etherapeuse autous</em> — and he healed them.</p>',
    "31": '<p><strong>hōste tous ochlous thaumasai bleponton kōphous lalountas</strong> — so that the crowds marveled, seeing mute people speaking — the healing list includes <em>kyllous hygieis</em> (crippled made sound), <em>chōlous peripatountas</em> (lame walking), <em>typhlous blepontas</em> (blind seeing): the same categories as the messianic answer to John (11:5). <em>Kai edoxasan ton theon Israēl</em> (and they glorified the God of Israel — <em>Israēl</em>: the God of Israel specifically, which suggests these crowds may be Gentiles marveling at Israel\'s God): the praise identifies the source of the healings as the covenant God.</p>',
    "32": '<p><strong>ho de Iēsous proskalesamenos tous mathētas autou eipen splanchnizomai epi ton ochlon</strong> — calling his disciples to him Jesus said: I have compassion for the crowd (<em>splanchnizomai</em>: the visceral compassion verb, used also in 9:36 and 14:14; here Jesus speaks the compassion explicitly rather than the narrator reporting it) — <em>hēmerai treis prosmenousin moi kai ouk echousin ti phagōsin</em> (they have remained with me three days and have nothing to eat): the three-day duration suggests a sustained teaching event, not a single encounter. <em>Kai apolusai autous nēsteis ou thelō</em> (and I do not want to send them away hungry — <em>ou thelō</em>: I am not willing; the verb of will).</p>',
    "33": '<p><strong>kai legousin autō hoi mathētai pothen hēmin en erēmia artoi tosoutoi</strong> — the disciples say to him: where in a deserted place do we have enough bread for such a crowd — the disciples\' question is remarkable given that they participated in the first feeding. Their failure to connect the two situations is not stupidity but a pattern of forgetting that Jesus will explicitly rebuke in 16:9-10. <em>Hōste chortasai ochlon tosouton</em> (so as to satisfy such a crowd — <em>chortasai</em>: to fill to satisfaction, the same verb as 14:20): the question expresses genuine inadequacy, not unbelief.</p>',
    "34": '<p><strong>kai legei autois ho Iēsous posous artous echete</strong> — Jesus says to them: how many loaves do you have? (<em>posous</em>: how many — the question is identical to Mark 8:5): <em>hoi de eipan hepta kai oligia ichthydia</em> (they said: seven, and a few small fish — <em>oligia ichthydia</em>: a few small fish; the diminutive <em>ichthydia</em> emphasizes their smallness): the inventory is different from the first feeding (five loaves + two fish) but equally inadequate for the crowd. The specific number seven will be recalled in 16:10.</p>',
    "35": '<p><strong>kai parangeilas tō ochlō anapesein epi tēn gēn</strong> — commanding the crowd to recline on the ground (<em>parangeilas</em> aorist participle of <em>parangellō</em>: to pass along an order, to command authoritatively): the command to sit is a direct action by Jesus, identical in structure to 14:19. The crowd\'s compliance before any food is visible is itself an act of trust. The reclining posture (<em>anapesein</em>) is the formal meal-posture, making the feeding a proper meal event.</p>',
    "36": '<p><strong>kai labōn tous hepta artous kai tous ichthyas eucharistēsas eklasen</strong> — taking the seven loaves and the fish, giving thanks he broke them (<em>eucharistēsas</em> aorist participle of <em>eucharistō</em>: to give thanks — distinguished from 14:19\'s <em>eulogēsen</em> (blessed/invoked blessing): the first feeding uses <em>eulogeō</em>, the Jewish <em>berakah</em> form; the second uses <em>eucharistō</em>, the word that gives "Eucharist" its name) — <em>kai edidou tois mathētais hoi de mathētai tois ochlois</em> (and he was giving to the disciples, and the disciples to the crowds): the distribution chain is identical to ch14.</p>',
    "37": '<p><strong>kai ephagon pantes kai echortasthēsan</strong> — they all ate and were satisfied (<em>echortasthēsan</em>: the satisfaction-verb, cf. 14:20) — <em>kai to perisseuon tōn klasmatōn ēran hepta spyridas plēreis</em> (and they picked up the leftover fragments, seven baskets full — <em>spyridas</em>: large wicker hampers, a different word from the <em>kophinoi</em> of 14:20 which were personal Jewish wicker baskets; <em>spyris</em> is a larger carrying-basket): the different basket-type is not incidental — Jesus specifically references both numbers and basket-types in 16:9-10, indicating the distinction matters for interpretation.</p>',
    "38": '<p><strong>hoi de esthiontes ēsan tetrakischilioi andres</strong> — those eating were four thousand men (<em>tetrakischilioi</em>: four thousand — a round number; the distinction between the first (five thousand) and second (four thousand) feedings suggests two separate events, not two versions of one) — <em>chōris gynaikōn kai paidiōn</em> (besides women and children — the same qualifier as 14:21): Matthew\'s consistent addition of women and children to the male count indicates the total was substantially more than four thousand.</p>',
    "39": '<p><strong>kai apolusas tous ochlous enebē eis to ploion kai ēlthen eis ta horia Magadan</strong> — dismissing the crowds he got into the boat and came to the region of Magadan (<em>apolusas</em>: having dismissed; <em>Magadan</em>: an otherwise unattested place name; Mark 8:10 has Dalmanutha; both may be variant names for the same location on the western shore of the Sea of Galilee): the geographical transition moves from the mountain-feeding to the sign-demand of ch16:1.</p>'
  },
  "16": {
    "1": '<p><strong>kai proselthontes hoi Pharisaioi kai Saddoukaioi peirazontes</strong> — the Pharisees and Sadducees came, testing him (<em>peirazontes</em> present participle of <em>peirazō</em>: testing with hostile intent — the same word used in 4:1 for Satan\'s temptation of Jesus) — <em>epērōtēsan auton sēmeion ek tou ouranou epideixai autois</em> (asked him to show them a sign from heaven — <em>ek tou ouranou</em>: from heaven, as distinct from earthly/miraculous signs; they want a cosmic, divine-authentication sign): the Pharisees and Sadducees are normally opponents; their united front signals the gravity of the test. The same demand (with "except the sign of Jonah") appears in 12:38-40.</p>',
    "2": '<p><strong>opsias genomenas legete eudia</strong> — evening coming, you say: fair weather (<em>opsias</em>: evening, the late afternoon sky before sunset; <em>eudia</em>: fair weather, clear sky) — <em>pyrrazei gar ho ouranos</em> (for the sky is red/fiery — <em>pyrrazei</em> present of <em>pyrrazō</em>: to be red like fire): the weather-reading examples work by the same logic as the sign-reading Jesus demands of them. Red sky at evening = good weather; red sky in the morning = storm. The observation is accurate meteorology for the Mediterranean.</p>',
    "3": '<p><strong>kai prōi sēmeron cheimōn</strong> — and in the morning, today stormy (<em>cheimōn</em>: storm, winter weather) — <em>pyrrazei gar stygnazon ho ouranos</em> (for the sky is red and threatening/overcast — <em>stygnazon</em>: dark, gloomy, threatening): the weather-sign contrast establishes the principle. <em>To men prosōpon tou ouranou ginōskete diakrinein</em> (you know how to discern the face of the sky — <em>diakrinein</em>: to distinguish, discern precisely): <em>ta de sēmeia tōn kairōn ou dynasthe</em> (but the signs of the times you cannot — <em>ta sēmeia tōn kairōn</em>: the signs of the appointed moments, the marks of the eschatological season Jesus\'s ministry inaugurates).</p>',
    "4": '<p><strong>genea ponēra kai moichalis sēmeion epizētei</strong> — a wicked and adulterous generation seeks a sign — the same verdict as 12:39. <em>Kai sēmeion ou dothēsetai autē ei mē to sēmeion Iōna</em> (and a sign will not be given except the sign of Jonah — the single exception: the death-and-resurrection sign): <em>kai katalipōn autous apēlthen</em> (and leaving them he went away): the departure is abrupt and complete. The Pharisees and Sadducees receive only the answer they already received in ch12; there is nothing more to say.</p>',
    "5": '<p><strong>kai elthontes hoi mathētai eis to peran epelathonto artous labein</strong> — coming to the other side the disciples forgot to take bread (<em>epelathonto</em> aorist of <em>epilanthanō</em>: to forget entirely — they had completely forgotten) — the transition from the sign-demand (v.4) to the disciples\' bread-forgetfulness (v.5) sets up the leaven-warning of v.6. The disciples\' physical bread-anxiety will be contrasted with the spiritual "leaven" warning Jesus is about to deliver; their confusion between literal and metaphorical bread (v.7) exposes their still-incomplete understanding.</p>',
    "6": '<p><strong>ho de Iēsous eipen autois horate kai prosechete apo tēs zymēs tōn Pharisaiōn kai Saddoukaiōn</strong> — Jesus said to them: see and beware of the leaven of the Pharisees and Sadducees (<em>horate kai prosechete</em>: two imperatives — see/look out and be careful; <em>prosechete apo</em>: guard yourselves from, beware of — a warning verb) — <em>zymēs tōn Pharisaiōn kai Saddoukaiōn</em> (the leaven of the Pharisees and Sadducees): v.12 decodes this as their teaching, but the disciples initially take it literally because they forgot bread.</p>',
    "7": '<p><strong>hoi de dielogizonto en heautois legontes hoti artous ouk elabomen</strong> — they were debating among themselves saying that we took no bread (<em>dielogizonto</em> imperfect of <em>dialogizomai</em>: were deliberating, reasoning back and forth — the same internal-reasoning verb as 9:3-4 where the scribes deliberated about blasphemy) — the disciples assume Jesus is criticizing them for the bread-forgetting rather than warning against a metaphorical contamination. Their literal-mindedness after two miraculous feedings is precisely what Jesus will rebuke in v.8-10.</p>',
    "8": '<p><strong>gnous de ho Iēsous eipen ti dialogizesthe en heautois oligopistoi</strong> — knowing this, Jesus said: why are you deliberating among yourselves, you of little faith (<em>oligopistoi</em>: the coined compound, plural — addressed to the whole group for the first time in this form): <em>hoti artous ouk echete</em> (that you have no bread?): the question is partly rhetorical — Jesus is not confused about what they are discussing but names their deliberation as the product of small faith. The bread-anxiety reveals that they have not drawn the lessons of the two feedings.</p>',
    "9": '<p><strong>oupō noeite</strong> — do you still not understand (<em>noeite</em>: perceive, apprehend — the intellectual perception verb; <em>oupō</em>: not yet, still not): <em>oude mnēmoneuete tous pente artous tōn pentakischiliōn kai posous kophinous elabete</em> (nor do you remember the five loaves for the five thousand and how many baskets you gathered — <em>kophinous</em>: the Jewish wicker baskets of ch14, named specifically to distinguish from the second feeding\'s <em>spyridas</em> in v.10): Jesus cites the specific basket-type from each feeding, showing the two events are distinct and both are to be remembered.</p>',
    "10": '<p><strong>oude tous hepta artous tōn tetrakischiliōn kai posous spyridas elabete</strong> — nor the seven loaves for the four thousand and how many baskets you gathered (<em>spyridas</em>: the large hampers of ch15 — Jesus uses the same word Matthew used in 15:37, confirming these are two distinct events, not one account retold): the juxtaposition of <em>kophinous</em> (ch14) and <em>spyridas</em> (ch15) in Jesus\'s own summary of both feedings demonstrates that Matthew\'s use of different basket-words is intentional and carries meaning: two feedings, two communities (Jewish/Gentile contexts suggested), two basket-types.</p>',
    "11": '<p><strong>pōs ou noeite hoti ou peri artou eipon hymin</strong> — how is it you do not understand that I did not speak to you about bread — the question is a gentle frustration: after two miraculous feedings, anxiety about physical bread is irrational. The disciples have a repeated inability to move from literal to metaphorical when Jesus uses material imagery. <em>Prosechete de apo tēs zymēs tōn Pharisaiōn kai Saddoukaiōn</em> (but beware of the leaven of the Pharisees and Sadducees): the repetition of the warning without decoding it invites the disciples to make the metaphorical move themselves.</p>',
    "12": '<p><strong>tote synēkan hoti ouk eipen prosechein apo tēs zymēs tōn artōn</strong> — then they understood that he did not say to beware of the leaven of bread (<em>synēkan</em> aorist of <em>syniēmi</em>: they understood at once — the breakthrough understanding that has been building through the chapter) — <em>alla apo tēs didachēs tōn Pharisaiōn kai Saddoukaiōn</em> (but from the teaching of the Pharisees and Sadducees): the decoding reveals that "leaven" = "teaching": pernicious, spreading influence. The sign-demand of v.1 and the return-with-no-bread of v.5 were both setups for the disciples to learn to read spiritual signs over physical ones.</p>',
    "13": '<p><strong>elthōn de ho Iēsous eis ta merē Kaisareias tēs Philippou</strong> — coming to the region of Caesarea Philippi (<em>Kaisareia hē Philippou</em>: Caesarea of Philip — the Hellenistic city built by Philip the Tetrarch near Banias/Paneas at the foot of Mount Hermon; a heavily Gentile city with a sanctuary to Pan, hence the ancient name Paneas — the northern limit of Jesus\'s recorded travels) — <em>ērōta tous mathētas autou legōn tina legousin hoi anthrōpoi einai ton huion tou anthrōpou</em> (he was asking his disciples saying: who do people say the Son of Man is?): the location — far from Jerusalem, in Gentile-associated territory — heightens the confession that follows.</p>',
    "14": '<p><strong>hoi de eipan hoi men Iōannēn ton baptistēn</strong> — they said: some say John the Baptist — the popular identifications (John the Baptist, Elijah, Jeremiah, one of the prophets) all have in common that they place Jesus within the prophetic tradition rather than exceeding it. <em>Alloi de Ēlian</em> (others Elijah): the Malachi-Elijah expectation (Mal 4:5). <em>Heteroi de Ieremian ē hena tōn prophētōn</em> (others Jeremiah or one of the prophets): Jeremiah\'s association with Jesus is unique to Matthew; the tradition of Jeremiah\'s return may relate to the legend of Jeremiah hiding the temple vessels before the exile.</p>',
    "15": '<p><strong>legei autois hymeis de tina me legete einai</strong> — he says to them: but who do you say I am (<em>hymeis de</em>: emphatic you — contrasted with "people" of v.13; the question now comes directly to the disciples; <em>tina</em>: who, what identity?) — the shift from third-person ("who do people say") to second-person ("who do you say") is the pivot of the entire Gospel to this point. The disciples have traveled with Jesus, received private explanations, witnessed miracles, and received special teaching. Now they must answer for themselves who they believe he is.</p>',
    "17": '<p><strong>apokritheis de ho Iēsous eipen autō makarios ei Simōn Bar Iōna</strong> — answering, Jesus said to him: blessed are you, Simon son of Jonah (<em>Bar Iōna</em>: Aramaic patronymic — son of Jonah/John; the Aramaic patronymic in a Greek text marks a moment of special personal address) — <em>hoti sarx kai haima ouk apekalypsēn soi</em> (because flesh and blood did not reveal this to you — <em>sarx kai haima</em>: the Semitic idiom for human capacity, human resources, the physical-creaturely realm): <em>alla ho patēr mou ho en tois ouranois</em> (but my Father who is in the heavens): the confession is declared a supernatural disclosure, not a reasoned conclusion reached by human intelligence.</p>',
    "19": '<p><strong>dōsō soi tas kleidas tēs basileias tōn ouranōn</strong> — I will give you the keys of the kingdom of the heavens (<em>kleidas</em>: keys — the instrument of opening and closing, granting or denying access; in Jewish imagery, the key-holder has administrative authority: the key of David in Isa 22:22; Rev 3:7) — <em>kai ho ean dēsēs epi tēs gēs estai dedemenon en tois ouranois</em> (and whatever you bind on earth will be bound in heaven — <em>dedemenon</em> perfect passive: will be in a state of having been bound — the perfect passive in heaven may indicate that heaven ratifies the earthly binding; the rabbinic formula for binding/loosing was used for prohibiting/permitting halakhic rulings, not just for church discipline): <em>kai ho ean lysēs epi tēs gēs estai lelumenon en tois ouranois</em> — and whatever you loose on earth will be loosed in heaven.</p>',
    "20": '<p><strong>tote diesteilato tois mathētais hina mēdeni eipōsin hoti autos estin ho Christos</strong> — then he charged the disciples that they should tell no one that he is the Messiah (<em>diesteilato</em> aorist of <em>diastellomai</em>: to give explicit orders, to charge strictly) — the messianic secret following Peter\'s confession is not denial of the title but management of its timing and interpretation. The disciples must not announce the Messiahship before its meaning has been defined by the passion (v.21). An uninterpreted "Messiah" announcement would be misunderstood in political terms; the passion must first reframe what "Messiah" means.</p>',
    "21": '<p><strong>apo tote ērxato ho Iēsous deiknynai tois mathētais autou</strong> — from that time Jesus began to show his disciples (<em>apo tote ērxato</em>: from that time he began — one of Matthew\'s structural markers; the first "from that time" is 4:17 at the start of the Galilean ministry; this second marks a new phase: the passion-instruction phase) — <em>hoti dei auton eis Ierosolyma apelthein</em> (that it is necessary for him to go to Jerusalem — <em>dei</em>: it is necessary, divinely necessary — not compelled externally but internally required by the divine plan): the first passion prediction names Jerusalem, suffering by elders/chief priests/scribes, death, and resurrection on the third day.</p>',
    "22": '<p><strong>kai proslabomenos auton ho Petros ērxato epitiman autō legōn</strong> — taking him aside Peter began to rebuke him saying (<em>proslabomenos</em>: taking aside — Peter separates Jesus from the others for the private rebuke; <em>ērxato epitiman</em>: began to rebuke — <em>epitimaō</em>, the rebuke-verb used for silencing demons and rebuking wind/waves) — <em>ileos soi kyrie</em> (God be merciful to you, Lord — <em>ileos soi</em>: may God be gracious/merciful to you; not a mere interjection but an invocation of divine protection): <em>ou mē estai soi touto</em> (this will never happen to you — the strongest possible negation).</p>',
    "23": '<p><strong>ho de strapheis tō Petrō eipen hypage opisō mou Satana</strong> — turning to Peter he said: get behind me, Satan (<em>strapheis</em>: turning — a deliberate physical reorientation; <em>hypage opisō mou</em>: go behind me — the discipleship-command reversed: Peter who was called to follow-behind-Jesus is now told to return to behind-Jesus, away from in-front-of-Jesus where he was blocking the path) — <em>skandalon ei emou</em> (you are a stumbling-block to me — <em>skandalon</em>: a trap, an obstacle, a stumbling-block — placed in Jesus\'s path): <em>hoti ou phroneis ta tou theou alla ta tōn anthrōpōn</em> (for you are minding the things of God, but the things of men — <em>phroneis</em>: the present tense of <em>phroneō</em>, to set the mind on, to be oriented toward).</p>',
    "24": '<p><strong>tote ho Iēsous eipen tois mathētais autou ei tis thelei opisō mou elthein</strong> — then Jesus said to his disciples: if anyone wants to come after me (<em>opisō mou elthein</em>: to come behind me — the standard discipleship formula) — <em>aparnēsasthō heauton kai aratō ton stauron autou kai akoloutheitō moi</em> (let him deny himself and take up his cross and follow me): three aorist imperatives forming the discipleship-definition: self-denial (<em>aparnēsasthō</em>: to deny completely, disown oneself — the same verb as Peter\'s denial in 26:70,72); cross-taking (<em>aratō ton stauron autou</em>: take up his cross — the specific instrument of execution; cf. 10:38); following (<em>akoloutheitō</em> present imperative: ongoing following).</p>',
    "25": '<p><strong>hos gar ean thelē tēn psychēn autou sōsai apolesei autēn</strong> — for whoever wants to save his life will lose it (<em>psychēn</em>: life/soul — the word spanning physical survival, personal identity, and the whole self; <em>sōsai</em>: to save, preserve; <em>apolesei</em> future: will lose, will destroy) — <em>hos d an apolese tēn psychēn autou heneken emou heurēsei autēn</em> (but whoever loses his life for my sake will find it — <em>heneken emou</em>: for my sake, on account of me — the criterion): the paradox operates on <em>psychē</em>: protecting the self-life destroys it; surrendering it to Jesus finds the true life. Cf. 10:39 where the same saying appears in the mission discourse.</p>',
    "26": '<p><strong>ti gar ōphelēthēsetai anthrōpos ean ton kosmon holon kerdēsē</strong> — for what will it profit a person if he gains the whole world (<em>ōphelēthēsetai</em> future passive of <em>ōpheleō</em>: what benefit will accrue; <em>kerdēsē</em> aorist subjunctive of <em>kerdainō</em>: to gain, to profit financially) — <em>tēn de psychēn autou zēmiōthē</em> (but loses his soul — <em>zēmiōthē</em> aorist passive of <em>zēmioō</em>: to suffer loss, to be penalized, to forfeit — a commercial/legal term for incurring a loss): <em>ē ti dōsei anthrōpos antallagna tēs psychēs autou</em> (or what will a person give in exchange for his soul — <em>antallagna</em>: a counter-exchange, the price paid to recover something surrendered).</p>',
    "27": '<p><strong>mellei gar ho huios tou anthrōpou erchesthai en tē doxē tou patros autou meta tōn angelōn autou</strong> — for the Son of Man is about to come in the glory of his Father with his angels (<em>mellei</em>: is about to, is going to — the verb of imminent futurity; <em>en tē doxē tou patros autou</em>: in the glory of his Father — the eschatological coming in divine glory) — <em>kai tote apodōsei hekastō kata tēn praxin autou</em> (and then he will repay each one according to his practice/actions — <em>praxin</em>: action, practice, deed — the Judgment involves what one habitually does, not merely a single act): the ground for the cross-bearing saying (v.24-26) is the coming judgment.</p>',
    "28": '<p><strong>amen legō hymin hoti eisin tines tōn hōde hestōtōn</strong> — truly I tell you there are some of those standing here (<em>tōn hōde hestōtōn</em>: those standing here — a specific reference to the physical persons present) — <em>oitines ou mē geusōntai thanatou heōs an idōsin ton huion tou anthrōpou erchomenon en tē basileia autou</em> (who will not taste death until they see the Son of Man coming in his kingdom — <em>geusōntai thanatou</em>: taste death, a Semitic idiom for experiencing death; <em>en tē basileia autou</em>: in his kingdom): the saying has generated sustained debate — interpretations include the Transfiguration (immediately following in 17:1-8), Pentecost, the destruction of Jerusalem, or the parousia.</p>'
  },
  "17": {
    "1": '<p><strong>kai meth hēmeras hex paralambanei ho Iēsous ton Petron kai Iakōbon kai Iōannēn ton adelphon autou</strong> — after six days Jesus takes Peter and James and John his brother (<em>meth hēmeras hex</em>: after six days — the specific time-reference connects this to the confession of 16:16; only the three members of the inner group are taken; cf. the same three at Gethsemane in 26:37) — <em>kai anapherei autous eis oros hypsēlon kat idian</em> (and leads them up on a high mountain privately — <em>anapherei</em>: to lead/carry up, an ascent-verb used in Heb 13:15 for offering sacrifice): the mountain is the locus of divine encounter throughout Matthew.</p>',
    "2": '<p><strong>kai metemorphōthē emprosthen autōn</strong> — and he was transfigured before them (<em>metemorphōthē</em> aorist passive of <em>metamorphoō</em>: to transform in form — not a change of outer costume but a radiance emerging from within; the passive voice implies the action is done to Jesus or occurs in him) — <em>kai elampsen to prosōpon autou hōs ho hēlios</em> (and his face shone like the sun — <em>elampsen</em> aorist of <em>lampō</em>: to shine, to radiate): the solar comparison echoes Moses\'s face after Sinai (Exod 34:29-35) but exceeds it: Moses\'s face reflected divine glory; Jesus\'s face is the source of its own radiance. <em>Ta de himatia autou egeneto leuka hōs to phōs</em> — his garments became white as the light.</p>',
    "3": '<p><strong>kai idou ōphthē autois Mōysēs kai Ēlias synlalounte met autou</strong> — and behold, there appeared to them Moses and Elijah talking with him (<em>ōphthē</em> aorist passive of <em>horaō</em>: were seen, appeared — the passive of revelation; <em>Mōysēs kai Ēlias</em>: Moses and Elijah represent the Law and the Prophets; Luke 9:31 adds that they spoke of Jesus\'s "departure/exodus" — <em>exodon</em>): the two figures who represent the entire Hebrew Scripture appear alongside Jesus, placing him as the fulfillment and culmination of both streams. <em>Synlalounte met autou</em> — conversing with him: an active dialogue, not a mere appearance.</p>',
    "4": '<p><strong>apokritheis de ho Petros eipen tō Iēsou kyrie kalon estin hēmas hōde einai</strong> — Peter answering said to Jesus: Lord, it is good for us to be here (<em>apokritheis</em>: answering — used even where no prior question was asked; Peter responds to the situation) — <em>ei theleis poiēsō hōde treis skēnas</em> (if you wish I will make here three tents/booths — <em>skēnas</em>: tents, booths, tabernacles; the Feast of Tabernacles/<em>Sukkot</em> involved building booths): Peter\'s impulse to build three equal shelters for Jesus, Moses, and Elijah misunderstands the hierarchy — Moses and Elijah are witnesses to Jesus, not equals. The cloud-voice corrects the equivalence.</p>',
    "6": '<p><strong>kai akousantes hoi mathētai epesan epi prosōpon autōn kai ephobēthēsan sphodra</strong> — hearing this the disciples fell on their faces and were very afraid (<em>epesan epi prosōpon autōn</em>: they fell on their faces — the prostration response to theophany; cf. Ezek 1:28; Dan 8:17; Rev 1:17; <em>ephobēthēsan sphodra</em>: were greatly afraid — <em>sphodra</em>: intensely, exceedingly): the divine voice from the cloud produces prostration, not the light or the figures. The <em>voice</em> is the locus of maximum terror, because it directly addresses them as hearers.</p>',
    "7": '<p><strong>kai prosēlthen ho Iēsous kai hapsamenpos autōn eipen</strong> — and Jesus coming touched them and said (<em>hapsamenps</em> aorist participle of <em>haptō</em>: to touch — the healing/comforting touch; Jesus has not departed; he is physically present and responds to their prostration with a touch): <em>egerthēte kai mē phobeisthe</em> (rise up and do not be afraid — <em>egerthēte</em> aorist passive imperative of <em>egeirō</em>: the resurrection verb used for ordinary rising; <em>mē phobeisthe</em> present imperative: do not be in a state of fear). The first word after the theophany is "rise up" — the resurrection vocabulary applied to the disciples\' prostration.</p>',
    "8": '<p><strong>eparantes de tous ophthalmous autōn oudena eidon ei mē auton Iēsoun monon</strong> — lifting up their eyes they saw no one except Jesus alone (<em>eparantes tous ophthalmous</em>: lifting up the eyes — the gesture of recovery from prostration, looking up after the fall; <em>monon</em>: alone, only): Moses and Elijah have withdrawn; the cloud has lifted. What remains after the theophany is Jesus alone. The singularity of "Jesus alone" is the interpretive key to the Transfiguration: Law and Prophets give way; Jesus stands as their fulfillment and summation.</p>',
    "9": '<p><strong>kai katabainontōn autōn ek tou orous eneteilato autois ho Iēsous legōn</strong> — as they were coming down from the mountain Jesus commanded them saying (<em>eneteilato</em> aorist of <em>entellomai</em>: to command, give an injunction) — <em>mēdeni eipēte to horama heōs hou ho huios tou anthrōpou ek nekrōn egerthē</em> (tell the vision to no one until the Son of Man has been raised from the dead — <em>to horama</em>: the vision, a visionary experience — the word for prophetic seeing; <em>heōs hou...egerthē</em>: until the Son of Man is raised — the resurrection is the condition for disclosure: the Transfiguration makes sense only from the other side of the resurrection).</p>',
    "10": '<p><strong>kai epērōtēsan auton hoi mathētai legontes</strong> — the disciples asked him saying — <em>ti oun hoi grammateis legousin hoti Ēlian dei elthein prōton</em> (why then do the scribes say Elijah must come first? — <em>Ēlian dei elthein prōton</em>: Elijah must come first; the expectation is Mal 4:5): the disciples\' question shows they understood the Transfiguration\'s Elijah-appearance as potentially the fulfillment of the Elijah-first expectation. Jesus\'s answer distinguishes between Elijah-in-type (John the Baptist, who has already come) and Elijah-as-person (who may still have an end-time role).</p>',
    "11": '<p><strong>ho de apokritheis eipen Ēlias men erchetai kai apokatastēsei panta</strong> — answering he said: Elijah indeed comes and will restore all things (<em>apokatastēsei</em> future of <em>apokathistēmi</em>: to restore to an original or proper state — the eschatological restoration word; cf. Acts 1:6; the same root as <em>apokatastasis</em>) — Jesus affirms the Elijah-first tradition as real; the question is whether it has been fulfilled or is still future. The present tense <em>erchetai</em> (comes, is coming) followed by the future <em>apokatastēsei</em> (will restore) suggests an ongoing or future role, not a completed one.</p>',
    "12": '<p><strong>legō de hymin hoti Ēlias ēdē ēlthen</strong> — but I tell you that Elijah has already come (<em>ēdē ēlthen</em>: has already come — the aorist with the adverb of current relevance) — <em>kai ouk epegnōsan auton alla epoiēsan en autō hosa ēthelēsan</em> (and they did not recognize him but did to him whatever they wished — <em>ouk epegnōsan</em>: did not recognize — the intensive recognition-verb in the negative; John came in the Elijah-role but was unrecognized): <em>houtōs kai ho huios tou anthrōpou mellei paschein hyp autōn</em> (so also the Son of Man is about to suffer at their hands): John\'s fate previews Jesus\'s fate; the pattern of rejection-of-God\'s-messenger repeats.</p>',
    "13": '<p><strong>tote synēkan hoi mathētai hoti peri Iōannou tou baptistou eipen autois</strong> — then the disciples understood that he spoke to them about John the Baptist (<em>synēkan</em> aorist of <em>syniēmi</em>: the understanding-breakthrough; the aorist marks the moment of comprehension): the understanding that Elijah-who-came = John-the-Baptist becomes explicit; they had the pieces from 11:14 (where Jesus said "if you are willing to accept it, he is Elijah who is to come") but the Transfiguration context makes it clear. The disciples\' understanding is developing through the Gospel by a series of such breakthrough moments.</p>',
    "14": '<p><strong>kai elthontōn pros ton ochlon prosēlthen autō anthrōpos gonyp etōn kai</strong> — coming to the crowd, a man came to him kneeling (<em>gonyp etōn</em>: kneeling, genuflecting — the posture of petition before authority; the same form of approach as the Canaanite woman in 15:25) — the scene shifts from the mountain of transfiguration to the ordinary crowd with its suffering and the disciples\' inability to help. The contrast between the mountain-glory and the valley-failure intensifies both events: the disciples\' spiritual position has not translated into healing capacity.</p>',
    "15": '<p><strong>kyrie eleēson mou ton huion hoti selēniazetai kai kakōs paschei</strong> — Lord, have mercy on my son for he is a lunatic and suffers terribly (<em>selēniazetai</em>: to be "moon-struck" — from <em>selēnē</em>: moon; the term for a condition associated with the lunar cycle, epilepsy or seizure disorder: <em>kakōs paschei</em>: suffers terribly — the generic suffering-formula) — <em>pollakis gar piptei eis to pyr kai pollakis eis to hydōr</em> (for often he falls into fire and often into water): the symptoms describe violent, dangerous falls associated with demonic seizure; the medical description and the demonic explanation coexist in the ancient framework.</p>',
    "16": '<p><strong>kai prosēnenka auton tois mathētais sou kai ouk ēdunēthēsan auton therapeusai</strong> — I brought him to your disciples and they were unable to heal him (<em>ouk ēdunēthēsan</em> aorist passive of <em>dynamai</em>: were not able — a total inability, not partial success): the failure is stark. The disciples were given authority over unclean spirits in 10:1 and 10:8; their failure here will be explained by Jesus in terms of faith-size rather than authority-absence. The father\'s report to Jesus, after the disciples\' failure, is an implicit appeal that what the disciples lacked, Jesus possesses.</p>',
    "17": '<p><strong>apokritheis de ho Iēsous eipen ō genea apistos kai diestrammenē</strong> — answering Jesus said: O unbelieving and perverted generation (<em>apistos</em>: without faith, faithless — the opposite of <em>pistos</em>/faithful; <em>diestrammenē</em> perfect passive participle of <em>diastrephō</em>: to twist thoroughly, to pervert — a generation that has been twisted out of its proper orientation) — <em>heōs pote meth hymōn esomai heōs pote anexomai hymōn</em> (how long will I be with you, how long will I put up with you — <em>anexomai</em>: to bear with, endure, put up with — a patience-exhaustion expression): the rebuke is addressed to the generation, not narrowly to the disciples, though the disciples\' failure is the trigger.</p>',
    "18": '<p><strong>kai epetimēsen autō ho Iēsous kai exēlthen ap autou to daimonion</strong> — Jesus rebuked it and the demon came out of him (<em>epetimēsen</em> aorist of <em>epitimaō</em>: to rebuke, command — the standard exorcism-rebuke verb; <em>exēlthen</em> aorist: went out completely): <em>kai etherapeuthē ho pais apo tēs hōras ekeinēs</em> (and the boy was healed from that hour — <em>tēs hōras ekeinēs</em>: from that hour — the same formula as 15:28 and 9:22, marking instantaneous healing): the cure is immediate; the preceding diagnosis and the coming explanation of the disciples\' failure frame it as a teaching event about faith.</p>',
    "19": '<p><strong>tote proselthontes hoi mathētai tō Iēsou kat idian eipon</strong> — then the disciples came to Jesus privately and said (<em>kat idian</em>: privately — the private teaching context that follows difficult public events throughout Matthew) — <em>dia ti hēmeis ouk ēdynēthēmen ekbalein auto</em> (why were we unable to drive it out? — <em>ekbalein</em>: to drive out — the exorcism verb): the question is sincere; the disciples do not doubt Jesus\'s authority but cannot explain their own failure. Jesus\'s answer addresses the root cause: faith-size, not authority-level.</p>',
    "20": '<p><strong>ho de legei autois dia tēn oligopistian hymōn</strong> — he says to them: because of your little faith (<em>oligopistian</em>: little faith — the noun form of the compound <em>oligopistos</em>; the only use of the noun in Matthew; the accusation is general, describing the disciples\' faith-level as insufficient) — <em>amen gar legō hymin ean echēte pistin hōs kokkos sinapeōs</em> (for truly I tell you, if you have faith like a mustard seed — <em>kokkos sinapeōs</em>: a grain of mustard, the proverbially smallest seed; here the comparison is not to the tree but to the grain): <em>ereite tō orei toutō metabēthi enteuthen ekei kai metabēsetai</em> — you will say to this mountain: move from here to there, and it will move. <em>Kai ouden adynatēsei hymin</em> — nothing will be impossible for you.</p>',
    "21": '<p><strong>touto de to genos ouk ekporeuetai ei mē en proseuchē kai nēsteia</strong> — but this kind does not go out except by prayer and fasting — the verse is absent from some early manuscripts (Sinaiticus, Vaticanus) but present in others and in Mark 9:29 (without "fasting"). If original to Matthew, it specifies that certain severe demonic cases require an intensified prayer-and-fasting posture beyond the general authority granted in 10:1. The note qualifies the faith-as-mustard-seed saying of v.20 without contradicting it: mustard-seed faith that operates through prayer and fasting.</p>',
    "22": '<p><strong>systrephomenōn de autōn en tē Galilaia eipen autois ho Iēsous</strong> — as they were gathering in Galilee Jesus said to them — <em>mellei ho huios tou anthrōpou paradidosthai eis cheiras anthrōpōn</em> (the Son of Man is about to be delivered into the hands of men — <em>paradidosthai</em> present passive infinitive of <em>paradidōmi</em>: to be delivered, handed over — the betrayal/passion vocabulary): the second passion prediction uses <em>paradidosthai</em>, linking the passion directly to the Judas-betrayal that will occur in ch26. The irony of "delivered into the hands of men" is that "Son of Man" (a divine figure) is handed over to human power.</p>',
    "23": '<p><strong>kai apoktenousin auton kai tē tritē hēmera egerthēsetai</strong> — and they will kill him, and on the third day he will be raised (<em>egerthēsetai</em> future passive of <em>egeirō</em>: will be raised — the divine passive: God raises the Son of Man who was killed by men) — <em>kai elypēthēsan sphodra</em> (and they were deeply grieved — <em>elypēthēsan sphodra</em>: were distressed exceedingly; <em>sphodra</em>: intensely): the disciples heard the passion prediction and were grieved without full understanding (Luke 9:45 notes they did not grasp it). The grief is genuine; the comprehension is partial; they cannot yet hold together death and resurrection as a unity.</p>',
    "24": '<p><strong>elthontōn de autōn eis Kapharnaoun prosēlthon hoi ta didrachma lambanontes tō Petrō</strong> — coming to Capernaum those who collect the two-drachma tax came to Peter (<em>didrachma</em>: two drachmas — the annual temple tax of half a shekel, based on Exod 30:13-16, collected for the Jerusalem Temple; every adult Jewish male paid this; the collectors approach Peter, not Jesus, perhaps because Peter is recognizable as the group\'s spokesperson): <em>ho didaskalos hymōn ou telei ta didrachma</em> (does not your teacher pay the two-drachma tax?): the question is not hostile but administrative.</p>',
    "25": '<p><strong>legei nai kai elthonta eis tēn oikian proephthasen auton ho Iēsous legōn</strong> — he says: yes. And coming into the house Jesus anticipated him saying (<em>proephthasen</em> aorist of <em>prophthanō</em>: to get ahead of, to anticipate — Jesus speaks first before Peter can report the exchange) — <em>ti soi dokei Simōn hoi basileis tēs gēs apo tinōn lambanousin telē ē kēnson</em> (what do you think, Simon? The kings of the earth — from whom do they collect toll or tax?): the question is practical and political: <em>apo tōn huiōn autōn ē apo tōn allotriōn</em> (from their own sons or from strangers?).</p>',
    "26": '<p><strong>eipantos de apo tōn allotriōn ephē autō ho Iēsous ara ge eleutheroi eisin hoi huioi</strong> — when he said: from the strangers, Jesus said to him: then the sons are free (<em>ara ge</em>: therefore indeed/then certainly — a strong logical inference; <em>eleutheroi eisin hoi huioi</em>: the sons are free, exempt — <em>eleutheros</em>: free person, not slave; free from the obligation): the argument: earthly kings exempt their own children from taxation; if God is the Father and the Temple is his house, then the Son of God is exempt from the Temple tax. The analogy is compressed but clear.</p>',
    "27": '<p><strong>hina de mē skandalisōmen autous</strong> — but so that we do not cause them to stumble (<em>skandalisōmen</em> aorist subjunctive of <em>skandalizō</em>: the stumbling-cause verb; <em>mē</em> + subjunctive: a prohibition of purpose) — the tax is voluntarily paid not because it is owed but to avoid causing offense. <em>Poreutheis eis thalassan bale agkistron</em> (going to the sea, throw out a hook — <em>agkistron</em>: a fishhook, not a net; a single targeted catch): <em>kai ton prōton ichthyn anabanta aron</em> (and taking the first fish that comes up — <em>ton prōton</em>: the very first): <em>kai anoixas to stoma autou heurēseis statēra</em> — opening its mouth you will find a stater (a four-drachma coin = one shekel, covering the tax for two people).</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-original', 'matthew', existing)
    print('Matthew 15-17 mkt-original written.')

if __name__ == '__main__':
    main()
